import java.io.*;
import java.util.ArrayList;

public class FileProcessor {

    public ArrayList<String> readTestData(String filename) {
        ArrayList<String> testData = new ArrayList<>();
        BufferedReader reader = null;

        try {
            reader = new BufferedReader(new FileReader(filename));
            String line;

            while ((line = reader.readLine()) != null) {
                if (!line.trim().isEmpty()) {
                    testData.add(line.trim());
                }
            }
        } catch (FileNotFoundException e) {
            System.out.println("File not found: " + filename);
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        } finally {
            try {
                if (reader != null) {
                    reader.close();
                }
            } catch (IOException e) {
                System.out.println("Error closing reader: " + e.getMessage());
            }
        }

        return testData;
    }

    public void writeTestReport(String filename, ArrayList<String> tests, ArrayList<String> results) {
        if (tests == null || results == null || tests.size() != results.size()) {
            System.out.println("Invalid test data");
            return;
        }

        try (BufferedWriter writer = new BufferedWriter(new FileWriter(filename))) {
            writer.write("=== Test Execution Report ===");
            writer.newLine();
            writer.write("Total Tests: " + tests.size());
            writer.newLine();
            writer.newLine();

            int passCount = 0;
            for (int i = 0; i < tests.size(); i++) {
                String status = results.get(i);
                writer.write(String.format("%d. %s - %s", (i + 1), tests.get(i), status));
                writer.newLine();

                if ("PASS".equals(status)) {
                    passCount++;
                }
            }

            writer.newLine();
            writer.write("Summary: " + passCount + " passed, " + (tests.size() - passCount) + " failed");
            writer.newLine();
            double passRate = (passCount * 100.0) / tests.size();
            writer.write(String.format("Pass Rate: %.2f%%", passRate));

        } catch (IOException e) {
            System.out.println("Error writing file: " + e.getMessage());
        }
    }

    public int countLines(String filename) {
        int count = 0;

        try (BufferedReader reader = new BufferedReader(new FileReader(filename))) {
            while (reader.readLine() != null) {
                count++;
            }
        } catch (FileNotFoundException e) {
            System.out.println("File not found: " + filename);
            return -1;
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
            return -1;
        }

        return count;
    }

    public boolean appendToFile(String filename, String content) {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(filename, true))) {
            writer.write(content);
            writer.newLine();
            return true;
        } catch (IOException e) {
            System.out.println("Error appending to file: " + e.getMessage());
            return false;
        }
    }

    public static void main(String[] args) {
        FileProcessor processor = new FileProcessor();

        // Create sample test data
        ArrayList<String> tests = new ArrayList<>();
        tests.add("LoginTest");
        tests.add("LogoutTest");
        tests.add("SearchTest");
        tests.add("CheckoutTest");

        ArrayList<String> results = new ArrayList<>();
        results.add("PASS");
        results.add("FAIL");
        results.add("PASS");
        results.add("PASS");

        // Write report
        processor.writeTestReport("test_report.txt", tests, results);
        System.out.println("Report written successfully");

        // Count lines
        int lines = processor.countLines("test_report.txt");
        System.out.println("Total lines in report: " + lines);

        // Append additional info
        processor.appendToFile("test_report.txt", "\n--- End of Report ---");
    }
}
